// LightFilter returns how much a block dims light (0 transparent … 15 opaque).
func LightFilter(state uint32) int {
	lo, hi := 0, len(lightFilterRanges)-1
	for lo <= hi {
		mid := (lo + hi) / 2
		r := lightFilterRanges[mid]
		switch {
		case state < r.Min:
			hi = mid - 1
		case state > r.Max:
			lo = mid + 1
		default:
			return r.Filter
		}
	}
	return Opaque // not listed → solid
}
